const memoizAddition = () => { 
  let cache = {}; 
 return (value) => { 
  if (value in cache) { 
   console.log('Fetching from cache'); 
   return cache[value]; // Here, cache.value cannot be used as property name starts with t
  } 
  else { 
   console.log('Calculating result'); 
   let result = value + 20; 
   cache[value] = result; 
   return result; 
  } 
 } 
} 
