Несмотря на то, что в JavaScript отсутствуют пространства имен, мы можем использовать Objects, IIFE для создания пространств имен.
я. Использование нотации объектного литерала: давайте обернем переменные и функции внутри литерала объекта.
который действует как пространство имен. После этого вы можете получить к ним доступ, используя нотацию объекта.
вар namespaceOne = { 
   функция func1() { 
       console.log("Это первое определение"); 
   } 
} 
вар namespaceTwo = { 
     функция func1() { 
         console.log("Это второе определение"); 
     } 




 } 
namespaceOne.func1(); // Это первое определение 
пространство именTwo.func1(); // Это второе определение 
я. Использование IIFE (выражение функции с немедленным вызовом): внешняя пара круглых скобок IIFE.
создает локальную область видимости для всего кода внутри него и делает анонимную функцию
функциональное выражение. Благодаря этому вы можете создать одну и ту же функцию в двух разных функциях.
выражения, которые будут действовать как пространство имен.
(функция() { 
 функция fun1(){ 
   console.log("Это первое определение"); 
   } fun1(); 
}()); 
(функция() { 
    функция fun1(){ 
       console.log("Это второе определение"); 
   } fun1(); 
 }()); 
я. Использование блока и объявления let/const. В ECMAScript 6 вы можете просто использовать блок и
объявление let, позволяющее ограничить область действия переменной блоком.
 { 
  let myFunction= функция fun1(){ 
  console.log("Это первое определение"); 
  } 
  мояФункция(); 
 } 
  //myFunction(): ReferenceError: myFunction не определена. 
 { 
  let myFunction= функция fun1(){ 
  console.log("Это второе определение"); 
  } 
  мояФункция(); 
 } 
  //myFunction(): ReferenceError: myFunction не определена.

answer_en:
Even though JavaScript lacks namespaces, we can use Objects , IIFE to create namespaces.
i. Using Object Literal Notation: Let's wrap variables and functions inside an Object literal
which acts as a namespace. After that you can access them using object notation
var namespaceOne = { 
   function func1() { 
       console.log("This is a first definition"); 
   } 
} 
var namespaceTwo = { 
     function func1() { 
         console.log("This is a second definition"); 
     } 




 } 
namespaceOne.func1(); // This is a first definition 
namespaceTwo.func1(); // This is a second definition 
i. Using IIFE (Immediately invoked function expression): The outer pair of parentheses of IIFE
creates a local scope for all the code inside of it and makes the anonymous function a
function expression. Due to that, you can create the same function in two different function
expressions to act as a namespace.
(function() { 
 function fun1(){ 
   console.log("This is a first definition"); 
   } fun1(); 
}()); 
(function() { 
    function fun1(){ 
       console.log("This is a second definition"); 
   } fun1(); 
 }()); 
i. Using a block and a let/const declaration: In ECMAScript 6, you can simply use a block and
a let declaration to restrict the scope of a variable to a block.
 { 
  let myFunction= function fun1(){ 
  console.log("This is a first definition"); 
  } 
  myFunction(); 
 } 
  //myFunction(): ReferenceError: myFunction is not defined. 
 { 
  let myFunction= function fun1(){ 
  console.log("This is a second definition"); 
  } 
  myFunction(); 
 } 
  //myFunction(): ReferenceError: myFunction is not defined.

