Вышеописанный процесс можно упростить, используя функцию генератора,
 константная коллекция = {
   один: 1, 
   два: 2, 




   три: 3, 
   [Символ.итератор]: функция * () { 
     for (введите это) { 
       дать этот [ключ]; 
     } 
   } 
 }; 
 const итератор = коллекция[Symbol.iterator](); 
 console.log(iterator.next());    // {значение: 1, выполнено: ложь} 
 console.log(iterator.next());    // {значение: 2, выполнено: ложь} 
